// Bookmark Manager API — entrypoint
// See PRODUCT_SPEC.md for full requirements
// The agent will build this out across tasks T1-T6

import express from "express";
import Database from "better-sqlite3";

const app = express();
const PORT = Number(process.env.PORT) || 3000;
const db = new Database("data.db");

type Bookmark = {
  id: number;
  url: string;
  title: string;
  description: string | null;
  folder_id: number | null;
  created_at: string;
  updated_at: string;
};

type Folder = {
  id: number;
  name: string;
  created_at: string;
  updated_at: string;
};

type FolderWithBookmarks = Folder & {
  bookmarks: Bookmark[];
};

app.use(express.json());

db.pragma("foreign_keys = ON");

db.exec(`
  CREATE TABLE IF NOT EXISTS folders (
    id INTEGER PRIMARY KEY,
    name TEXT NOT NULL,
    created_at TEXT NOT NULL,
    updated_at TEXT NOT NULL
  );

  CREATE TABLE IF NOT EXISTS bookmarks (
    id INTEGER PRIMARY KEY,
    url TEXT NOT NULL,
    title TEXT NOT NULL,
    description TEXT,
    folder_id INTEGER,
    created_at TEXT NOT NULL,
    updated_at TEXT NOT NULL,
    FOREIGN KEY (folder_id) REFERENCES folders(id) ON DELETE SET NULL
  )
`);

const bookmarkColumns = db.prepare("PRAGMA table_info(bookmarks)").all() as Array<{ name: string }>;
if (!bookmarkColumns.some((column) => column.name === "folder_id")) {
  db.prepare("ALTER TABLE bookmarks ADD COLUMN folder_id INTEGER REFERENCES folders(id) ON DELETE SET NULL").run();
}

const getBookmarkById = (id: number): Bookmark | undefined => {
  return db
    .prepare("SELECT id, url, title, description, folder_id, created_at, updated_at FROM bookmarks WHERE id = ?")
    .get(id) as Bookmark | undefined;
};

const getFolderById = (id: number): Folder | undefined => {
  return db.prepare("SELECT id, name, created_at, updated_at FROM folders WHERE id = ?").get(id) as
    | Folder
    | undefined;
};

const getBookmarksByFolderId = (folderId: number): Bookmark[] => {
  return db
    .prepare(
      "SELECT id, url, title, description, folder_id, created_at, updated_at FROM bookmarks WHERE folder_id = ? ORDER BY id ASC",
    )
    .all(folderId) as Bookmark[];
};

const parsePositiveId = (rawId: string): number | null => {
  const id = Number(rawId);
  return Number.isInteger(id) && id > 0 ? id : null;
};

const readRequiredString = (value: unknown): string | null => {
  if (typeof value !== "string") {
    return null;
  }

  const trimmed = value.trim();
  return trimmed.length > 0 ? trimmed : null;
};

const readOptionalDescription = (value: unknown): string | null => {
  if (value === undefined || value === null) {
    return null;
  }

  return typeof value === "string" ? value : String(value);
};

const readOptionalFolderId = (value: unknown): number | null | undefined => {
  if (value === undefined) {
    return undefined;
  }

  if (value === null) {
    return null;
  }

  const folderId = typeof value === "number" ? value : Number(value);
  return Number.isInteger(folderId) && folderId > 0 ? folderId : undefined;
};

const resolveFolderId = (value: unknown): { ok: true; folderId: number | null } | { ok: false } => {
  const folderId = readOptionalFolderId(value);

  if (folderId === undefined) {
    return { ok: false };
  }

  if (folderId !== null && !getFolderById(folderId)) {
    return { ok: false };
  }

  return { ok: true, folderId };
};

app.get("/health", (_req, res) => {
  res.status(200).json({ status: "ok" });
});

app.post("/folders", (req, res) => {
  const name = readRequiredString(req.body?.name);

  if (!name) {
    return res.status(400).json({ error: "name is required" });
  }

  const now = new Date().toISOString();
  const result = db.prepare("INSERT INTO folders (name, created_at, updated_at) VALUES (?, ?, ?)").run(name, now, now);
  const folder = getFolderById(Number(result.lastInsertRowid));

  return res.status(201).json(folder);
});

app.get("/folders", (_req, res) => {
  const folders = db.prepare("SELECT id, name, created_at, updated_at FROM folders ORDER BY id ASC").all() as Folder[];
  return res.status(200).json(folders);
});

app.get("/folders/:id", (req, res) => {
  const id = parsePositiveId(req.params.id);
  if (!id) {
    return res.status(404).json({ error: "folder not found" });
  }

  const folder = getFolderById(id);
  if (!folder) {
    return res.status(404).json({ error: "folder not found" });
  }

  const response: FolderWithBookmarks = {
    ...folder,
    bookmarks: getBookmarksByFolderId(id),
  };

  return res.status(200).json(response);
});

app.put("/folders/:id", (req, res) => {
  const id = parsePositiveId(req.params.id);
  if (!id) {
    return res.status(404).json({ error: "folder not found" });
  }

  const existing = getFolderById(id);
  if (!existing) {
    return res.status(404).json({ error: "folder not found" });
  }

  const name = readRequiredString(req.body?.name);
  if (!name) {
    return res.status(400).json({ error: "name must be non-empty" });
  }

  db.prepare("UPDATE folders SET name = ?, updated_at = ? WHERE id = ?").run(name, new Date().toISOString(), id);

  return res.status(200).json(getFolderById(id));
});

app.delete("/folders/:id", (req, res) => {
  const id = parsePositiveId(req.params.id);
  if (!id) {
    return res.status(404).json({ error: "folder not found" });
  }

  const existing = getFolderById(id);
  if (!existing) {
    return res.status(404).json({ error: "folder not found" });
  }

  const deleteFolder = db.transaction((folderId: number) => {
    db.prepare("UPDATE bookmarks SET folder_id = NULL, updated_at = ? WHERE folder_id = ?").run(
      new Date().toISOString(),
      folderId,
    );
    db.prepare("DELETE FROM folders WHERE id = ?").run(folderId);
  });

  deleteFolder(id);
  return res.status(204).send();
});

app.post("/bookmarks", (req, res) => {
  const url = readRequiredString(req.body?.url);
  const title = readRequiredString(req.body?.title);

  if (!url) {
    return res.status(400).json({ error: "url is required" });
  }

  if (!title) {
    return res.status(400).json({ error: "title is required" });
  }

  const folderResult = resolveFolderId(req.body?.folder_id ?? null);
  if (!folderResult.ok) {
    return res.status(400).json({ error: "folder_id must reference an existing folder" });
  }

  const now = new Date().toISOString();
  const result = db
    .prepare(
      "INSERT INTO bookmarks (url, title, description, folder_id, created_at, updated_at) VALUES (?, ?, ?, ?, ?, ?)",
    )
    .run(url, title, readOptionalDescription(req.body?.description), folderResult.folderId, now, now);

  const bookmark = getBookmarkById(Number(result.lastInsertRowid));
  return res.status(201).json(bookmark);
});

app.get("/bookmarks", (_req, res) => {
  const bookmarks = db
    .prepare("SELECT id, url, title, description, folder_id, created_at, updated_at FROM bookmarks ORDER BY id ASC")
    .all() as Bookmark[];

  res.status(200).json(bookmarks);
});

app.get("/bookmarks/:id", (req, res) => {
  const id = parsePositiveId(req.params.id);
  if (!id) {
    return res.status(404).json({ error: "bookmark not found" });
  }

  const bookmark = getBookmarkById(id);
  if (!bookmark) {

    return res.status(404).json({ error: "bookmark not found" });
  }

  return res.status(200).json(bookmark);
});

app.put("/bookmarks/:id", (req, res) => {
  const id = parsePositiveId(req.params.id);
  if (!id) {
    return res.status(404).json({ error: "bookmark not found" });
  }

  const existing = getBookmarkById(id);
  if (!existing) {
    return res.status(404).json({ error: "bookmark not found" });
  }

  const url = req.body?.url === undefined ? existing.url : readRequiredString(req.body.url);
  const title = req.body?.title === undefined ? existing.title : readRequiredString(req.body.title);

  if (!url) {
    return res.status(400).json({ error: "url must be non-empty" });
  }

  if (!title) {
    return res.status(400).json({ error: "title must be non-empty" });
  }

  const description =
    req.body?.description === undefined ? existing.description : readOptionalDescription(req.body.description);
  let resolvedFolderId = existing.folder_id;

  if (req.body?.folder_id !== undefined) {
    const folderResult = resolveFolderId(req.body.folder_id);
    if (!folderResult.ok) {
      return res.status(400).json({ error: "folder_id must reference an existing folder" });
    }

    resolvedFolderId = folderResult.folderId;
  }

  const updatedAt = new Date().toISOString();

  db.prepare("UPDATE bookmarks SET url = ?, title = ?, description = ?, folder_id = ?, updated_at = ? WHERE id = ?").run(
    url,
    title,
    description,
    resolvedFolderId,
    updatedAt,
    id,
  );

  return res.status(200).json(getBookmarkById(id));
});

app.delete("/bookmarks/:id", (req, res) => {
  const id = parsePositiveId(req.params.id);
  if (!id) {
    return res.status(404).json({ error: "bookmark not found" });
  }

  const result = db.prepare("DELETE FROM bookmarks WHERE id = ?").run(id);
  if (result.changes === 0) {
    return res.status(404).json({ error: "bookmark not found" });
  }

  return res.status(204).send();
});

app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

export default app;

